class Solution:
    def maximalSquare(self, matrix):
        m = len(matrix)
        n = len(matrix[0])
        # prefix sums of ones for O(1) rectangle-of-ones checks
        pre = [[0] * (n + 1) for _ in range(m + 1)]
        for i in range(m):
            for j in range(n):
                pre[i + 1][j + 1] = pre[i][j + 1] + pre[i + 1][j] - pre[i][j] + (1 if matrix[i][j] == '1' else 0)
        best = 0
        max_side = min(m, n)
        for i in range(m):
            for j in range(n):
                for s in range(best + 1, max_side + 1):
                    if i + s > m or j + s > n:
                        break
                    ones = pre[i + s][j + s] - pre[i][j + s] - pre[i + s][j] + pre[i][j]
                    if ones == s * s:
                        best = s
        return best * best

