class Solution:
    def maximalSquare(self, matrix):
        m = len(matrix)
        n = len(matrix[0])
        dp = [0] * (n + 1)
        best = 0
        for i in range(m):
            prev = 0
            for j in range(n):
                temp = dp[j + 1]
                if matrix[i][j] == '1':
                    dp[j + 1] = min(dp[j], dp[j + 1], prev) + 1
                    best = max(best, dp[j + 1])
                else:
                    dp[j + 1] = 0
                prev = temp
        return best * best

