var maximalSquare = function(matrix) {
    const m = matrix.length, n = matrix[0].length;
    const dp = new Array(n + 1).fill(0);
    let best = 0;
    for (let i = 0; i < m; i++) {
        let prev = 0;
        for (let j = 0; j < n; j++) {
            const temp = dp[j + 1];
            if (matrix[i][j] === '1') {
                dp[j + 1] = Math.min(dp[j], dp[j + 1], prev) + 1;
                best = Math.max(best, dp[j + 1]);
            } else {
                dp[j + 1] = 0;
            }
            prev = temp;
        }
    }
    return best * best;
};
